<?php
session_start(); require 'db_connection.php'; require_once 'helpers.php'; require_login(); $conn=OpenCon(); $userId=current_user_id();
$stmt=$conn->prepare("SELECT * FROM tickets WHERE user_id=? AND status='open' LIMIT 1"); $stmt->bind_param("i",$userId); $stmt->execute(); $ticket=$stmt->get_result()->fetch_assoc();
if(isset($_POST['open_ticket'])){ $stmt=$conn->prepare("INSERT INTO tickets (user_id) VALUES (?)"); $stmt->bind_param("i",$userId); $stmt->execute(); redirect('contact.php'); }
if(isset($_POST['send']) && $ticket){ $msg=trim($_POST['message']); if($msg!==''){ $sender='user'; $stmt=$conn->prepare("INSERT INTO ticket_messages (ticket_id,sender,message) VALUES (?,?,?)"); $stmt->bind_param("iss",$ticket['id'],$sender,$msg); $stmt->execute(); redirect('contact.php'); }}
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Contact Us</title><link rel="stylesheet" href="css/style.css"></head><body><?php include 'navbar.php'; ?><div class="container"><h2 class="center">Contact Admin</h2><?php if(!$ticket):?><div class="card center"><p>You do not have an open ticket.</p><form method="post"><button name="open_ticket">Open New Ticket</button></form></div><?php else:?><div class="card"><?php $mstmt=$conn->prepare("SELECT * FROM ticket_messages WHERE ticket_id=? ORDER BY created_at"); $mstmt->bind_param("i",$ticket['id']); $mstmt->execute(); $msgs=$mstmt->get_result(); while($m=$msgs->fetch_assoc()):?><p><b>[<?=e($m['created_at'])?>] <?=e($m['sender'])?>:</b> <?=e($m['message'])?></p><?php endwhile;?></div><form method="post" class="card"><textarea name="message" rows="4" required placeholder="Write your message..."></textarea><button name="send">Send</button></form><?php endif;?></div></body></html>
